import {
  Box,
  Header,
  Icon,
  Modal,
  StatusBar,
} from '@semparar/design-system-app';
import { ModalLoadingBox, Text } from '@semparar/design-system-app/fintech';
import React, { FC } from 'react';
import { ScrollView } from 'react-native';

import { eventSelectContent } from '~/constants/functions';
import theme from '../../../TO_BE_REMOVED/theme';
import WrapperKeyboardAvoiding from '../WrapperKeyboardAvoiding';
import { BasicScreenViewProps } from './Models';
import { Container, Overlay } from './styles';

const BasicScreenView: FC<BasicScreenViewProps> = ({
  children,
  title = '',
  hasLeftIcon = true,
  leftIcon = 'icon-back',
  leftIconOnPress = () => {},
  hasRightIcon = false,
  rightIcon = 'icon-close',
  rightIconOnPress = () => {},
  statusBarBg = 'BRAND_BASE_01',
  statusBarProps = {
    barStyle: 'light-content',
  },
  isLoading = false,
  bgColor = 'BRAND_COMPLEMENT_03',
  hasScroll = false,
  hasHeader = true,
  headerTitle,
  scrollViewProps,
  titleColor,
  leftIconColor,
  rightIconColor,
  rightSecondaryIcon,
  rightSecondaryIconNot,
  testID,
  throttle,
  ref,
  showValue,
  setShowValue,
  errorButtonOnPress,
  currentRouteName,
  handleGoToHome,
  hasError,
  handleClose,
}) => {
  return (
    <WrapperKeyboardAvoiding>
      <ModalLoadingBox
        onClose={() => null}
        visible={isLoading}
        numberOfLines={1}
        title="Aguarde..."
      />
      <Container testID={testID} bgColor={bgColor}>
        <StatusBar bgColor={theme.colors[statusBarBg]} {...statusBarProps} />
        {hasHeader ? (
          <Header
            title={title}
            iconLeft={leftIcon}
            iconRight={rightIcon}
            hideLeftIcon={!hasLeftIcon}
            isOption={hasRightIcon}
            onBack={leftIconOnPress}
            onPressIconRight={rightIconOnPress}
            titleColor={titleColor}
            colorFirstIcon={leftIconColor}
            colorLastIcon={rightIconColor}
            testID="icon-home-button"
          />
        ) : null}
        {headerTitle ? (
          <Box
            width="100%"
            bgColor="BRAND_COMPLEMENT_01"
            pd="innerLarge"
            direction
            justify="space-between"
          >
            <Text type="subtitleXXXXL" color="#e6e6e6">
              {headerTitle}
            </Text>
            <Box direction justify="space-between">
              {rightSecondaryIcon && (
                <Icon
                  mr="middle"
                  onPress={() => setShowValue?.(!showValue)}
                  name={showValue ? rightSecondaryIcon : rightSecondaryIconNot}
                  color="#e6e6e6"
                />
              )}
              <Icon
                name={rightIcon}
                color="#e6e6e6"
                onPress={rightIconOnPress}
              />
            </Box>
          </Box>
        ) : null}
        {hasScroll ? (
          <ScrollView
            ref={ref}
            {...scrollViewProps}
            scrollEnabled={hasScroll}
            scrollEventThrottle={throttle ?? 0}
            contentContainerStyle={{ flexGrow: 1 }}
          >
            {children}
          </ScrollView>
        ) : (
          children
        )}

        {hasError && (
          <Overlay>
            <Modal
              iconBgColor="DENY_COLOR_03"
              visible={hasError}
              icon="icon-circle-alert"
              onPressFirstButton={() => {
                eventSelectContent({
                  content_type: 'cta',
                  content_id: 'tentar_novamente_erro',
                  location_1: 'monetizacao',
                  location_2: 'spmais',
                  location_3: currentRouteName,
                });
                errorButtonOnPress();
              }}
              onPressSecondButton={handleGoToHome}
              textFirstButton="Tentar novamente"
              textSecondButton="Voltar para Home"
              subTitle="Ops, algo deu errado..."
              colorSubtitle="BRAND_COMPLEMENT_01"
              iconColor="DENY_COLOR_01"
              testID="modalApiError"
              description="Por favor, tente novamente."
              onClose={handleClose}
            />
          </Overlay>
        )}
      </Container>
    </WrapperKeyboardAvoiding>
  );
};

export default BasicScreenView;

import { Box, Image } from '@semparar/design-system-app';
import { Text } from '@semparar/design-system-app/fintech';
import React from 'react';
import { Animated } from 'react-native';
import arrow from '../../../assets/images/arrow.png';
import { AnimationArrowsViewProps } from './Models';
import { Container } from './styles';

const AnimationArrowsView = ({
  arrow1Move,
  arrow1Fade,
  arrow2Move,
  arrow2Fade,
  arrow3Move,
  arrow3Fade,
}: AnimationArrowsViewProps) => {
  return (
    <Container testID="AnimationArrowsView">
      <Box
        justify="center"
        align="center"
        width="100%"
        overflow="hidden"
        height={175}
      >
        <Box direction justify="center">
          <Animated.View
            style={[
              {
                position: 'absolute',
                transform: [{ translateX: -35 }, { translateY: arrow1Move }],
                opacity: arrow1Fade,
              },
            ]}
          >
            <Image height={41} width={30} source={arrow} />
          </Animated.View>
          <Animated.View
            style={[
              {
                position: 'absolute',
                transform: [{ translateY: arrow2Move }],
                opacity: arrow2Fade,
              },
            ]}
          >
            <Image height={41} width={30} source={arrow} />
          </Animated.View>
          <Animated.View
            style={[
              {
                position: 'absolute',
                transform: [{ translateX: 30 }, { translateY: arrow3Move }],
                opacity: arrow3Fade,
              },
            ]}
          >
            <Image height={41} width={30} source={arrow} />
          </Animated.View>
        </Box>
      </Box>
      <Text align="center" mt="middle" type="subtitleLarger">
        Estamos carregando suas informações...
      </Text>
    </Container>
  );
};

export default AnimationArrowsView;

